            'model' => 'vertex_ai/gemini-2.0-flash',
            'stream' => true,
        ]));
        $result = $client->chatStream($request);
        $__camel = function ($v) use (&$__camel) {
            if (is_array($v)) {
                $out = [];
                foreach ($v as $k => $vv) {
                    $key = is_string($k) ? lcfirst(str_replace(' ', '', ucwords(str_replace('_', ' ', $k)))) : $k;
                    $out[$key] = $__camel($vv);
                }
                return array_keys($out) === range(0, count($out) - 1) ? $out : (object) $out;
            }
            if (is_object($v)) {
                $out = new \stdClass();
                foreach (get_object_vars($v) as $k => $vv) {
                    $key = lcfirst(str_replace(' ', '', ucwords(str_replace('_', ' ', $k))));
                    $out->{$key} = $__camel($vv);
                }
                return $out;
            }
            return $v;
        };
        $__decode_chunk = fn($c) => $__camel(
            is_string($c)
                ? json_decode($c, true)
                : (is_array($c) || is_object($c) ? json_decode(json_encode($c), true) : $c),
        );
        $chunks = is_string($result)
            ? array_map($__decode_chunk, (array) (json_decode($result, true) ?: []))
            : (
                is_array($result)
                    ? array_map($__decode_chunk, $result)
                    : array_map($__decode_chunk, iterator_to_array($result))
            );

        $this->assertGreaterThanOrEqual(2, count($chunks), 'expected >= 2 chunks');
        $this->assertEquals('One Two Three', implode('', array_map(
            fn($c) => $c->choices[0]->delta->content ?? '',
            $chunks,
        )));
        $this->assertTrue(!empty($chunks) && isset(end($chunks)->choices[0]->finishReason));
    }
}
